  1	import * as React from 'react';
  2	import { pluralize } from '@odf/core/components/utils';
  3	import { ReplicationType, STORAGE_ID_LABEL_KEY } from '@odf/mco/constants';
  4	import { getDRPolicyResourceObj, useACMSafeFetch } from '@odf/mco/hooks';
  5	import {
  6	  DRPolicyKind,
  7	  MirrorPeerKind,
  8	  SearchResult,
  9	  SearchResultItemType,
 10	} from '@odf/mco/types';
 11	import {
 12	  getLabelsFromSearchResult,
 13	  getReplicationType,
 14	  queryStorageClassesUsingClusterNames,
 15	} from '@odf/mco/utils';
 16	import { fireManagedClusterView } from '@odf/mco/utils/managed-cluster-view';
 17	import {
 18	  getName,
 19	  StatusBox,
 20	  CEPH_PROVISIONERS,
 21	  StorageClassModel,
 22	  IBM_PROVISIONERS,
 23	} from '@odf/shared';
 24	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 25	import {
 26	  StatusIconAndText,
 27	  useK8sWatchResource,
 28	} from '@openshift-console/dynamic-plugin-sdk';
 29	import { TFunction } from 'react-i18next';
 30	import {
 31	  Alert,
 32	  AlertVariant,
 33	  Spinner,
 34	  Text,
 35	  TextVariants,
 36	} from '@patternfly/react-core';
 37	import { TimesIcon } from '@patternfly/react-icons';
 38	import {
 39	  DRPolicyAction,
 40	  DRPolicyActionType,
 41	  ManagedClusterInfoType,
 42	} from './utils/reducer';
 43	import './create-dr-policy.scss';
 44	import '../../style.scss';
 45	
 46	const PROVISIONER = 'provisioner';
 47	const EXTERNAL_DEPLOYMENT_TYPE = 'external';
 48	
 49	const checkSyncPolicyExists = (
 50	  clusters: string[],
 51	  drPolicies: DRPolicyKind[]
 52	): boolean =>
 53	  drPolicies.some((drPolicy) => {
 54	    const { drClusters } = drPolicy.spec;
 55	    const isSyncPolicy = getReplicationType(drPolicy) === ReplicationType.SYNC;
 56	    return (
 57	      isSyncPolicy && drClusters.every((cluster) => clusters.includes(cluster))
 58	    );
 59	  });
 60	
 61	const checkClientToODFPeering = (clusters: ManagedClusterInfoType[]): boolean =>
 62	  // ODF cluster to client peering is not supported for DR.
 63	  !!clusters[0]?.odfInfo?.storageClusterInfo?.clientInfo !==
 64	  !!clusters[1]?.odfInfo?.storageClusterInfo?.clientInfo;
 65	
 66	const verifyMirrorPeerExistence = (
 67	  clusters: ManagedClusterInfoType[],
 68	  mirrorPeers: MirrorPeerKind[]
 69	): boolean => {
 70	  const peerNames: string[] = clusters.map(getName);
 71	  const mirrorPeer: MirrorPeerKind = mirrorPeers.find((mirrorPeer) =>
 72	    mirrorPeer.spec?.items?.some((item) => peerNames.includes(item.clusterName))
 73	  );
 74	  const existingPeerNames =
 75	    mirrorPeer?.spec?.items?.map((item) => item.clusterName) ?? [];
 76	  // When one of the chosen clusters is already paired with another cluster, return True.
 77	  return existingPeerNames.length > 0
 78	    ? existingPeerNames.sort().join(',') !== peerNames.sort().join(',')
 79	    : false;
 80	};
 81	
 82	const validateClusterSelection = (
 83	  clusters: ManagedClusterInfoType[],
 84	  drPolicies: DRPolicyKind[],
 85	  mirrorPeers: MirrorPeerKind[],
 86	  isStorageClassesValid: boolean
 87	): ValidationType => {
 88	  const validation: ValidationType = clusters.reduce(
 89	    (acc, cluster) => {
 90	      const name = getName(cluster);
 91	      const { odfInfo } = cluster;
 92	      const { isValidODFVersion, storageClusterInfo, storageClusterCount } =
 93	        cluster?.odfInfo || {};
 94	      if (!odfInfo || storageClusterCount === 0) {
 95	        acc.clusterValidation.clustersWithoutODF.push(name);
 96	      }
 97	      if (!isValidODFVersion) {
 98	        acc.clusterValidation.clustersWithUnsupportedODF.push(name);
 99	      }
100	      if (!storageClusterInfo?.cephFSID) {
101	        acc.clusterValidation.clustersWithUnsuccessfullODF.push(name);
102	      }
103	      if (storageClusterCount > 1) {
104	        acc.clusterValidation.clustersWithMultipleStorageInstances.push(name);
105	      }
106	      return acc;
107	    },
108	    {
109	      clusterValidation: {
110	        clustersWithUnsupportedODF: [],
111	        clustersWithoutODF: [],
112	        clustersWithUnsuccessfullODF: [],
113	        clustersWithMultipleStorageInstances: [],
114	      },
115	    } as ValidationType
116	  );
117	
118	  validation.peeringValidation = {
119	    unSupportedPeering: checkClientToODFPeering(clusters),
120	    invalidPolicyCreation:
121	      checkSyncPolicyExists(clusters.map(getName), drPolicies) ||
122	      verifyMirrorPeerExistence(clusters, mirrorPeers),
123	    unSupportedStorageClasses: !isStorageClassesValid,
124	  };
125	
126	  return validation;
127	};
128	
129	const getPeeringValidationMessage = (
130	  peeringValidation: PeeringValidationType,
131	  t: TFunction<string>
132	): PeeringValidationMessageType => {
133	  if (peeringValidation.unSupportedPeering) {
134	    return {
135	      title: t('Unsupported peering configuration.'),
136	      description: t(
137	        'The selected clusters cannot be peered due to a mismatch in types. ' +
138	          'Ensure both clusters are of the same type to continue.'
139	      ),
140	    };
141	  } else if (peeringValidation.invalidPolicyCreation) {
142	    return {
143	      title: t('Selected clusters cannot be used to create a DRPolicy.'),
144	      description: t(
145	        'A mirror peer configuration already exists for one or more of the selected clusters, ' +
146	          'either from an existing or deleted DR policy. To create a new DR policy with these clusters, ' +
147	          'delete any existing mirror peer configurations associated with them and try again.'
148	      ),
149	    };
150	  } else if (peeringValidation.unSupportedStorageClasses) {
151	    return {
152	      title: t('Cannot proceed with policy creation.'),
153	      description: t(
154	        'No common storage class found for the selected managed clusters. ' +
155	          'To create a DR policy, a common storage class must exist, ' +
156	          'if not configured already, provision a common storage class and try again.'
157	      ),
158	    };
159	  }
160	};
161	
162	const getClusterValidationMessage = (
163	  clusterName: string,
164	  clusterValidation: ClusterValidationType,
165	  requiredODFVersion: string,
166	  t: TFunction<string>
167	): string[] => {
168	  const errorMessages: string[] = [];
169	
170	  clusterValidation?.clustersWithUnsupportedODF.includes(clusterName) &&
171	    errorMessages.push(
172	      t('Data foundation must be {{version}} or above.', {
173	        version: requiredODFVersion,
174	      })
175	    );
176	
177	  clusterValidation?.clustersWithUnsuccessfullODF.includes(clusterName) &&
178	    errorMessages.push(t('Must be connected to RHCS.'));
179	
180	  clusterValidation?.clustersWithMultipleStorageInstances.includes(
181	    clusterName
182	  ) && errorMessages.push(t('The cluster has multiple storage instances.'));
183	
184	  return errorMessages;
185	};
186	
187	const ClusterValidationMessage: React.FC<ClusterValidationMessageProps> = ({
188	  clusterName,
189	  clusterValidation,
190	  requiredODFVersion,
191	}) => {
192	  const { t } = useCustomTranslation();
193	  const errorMessages: string[] = getClusterValidationMessage(
194	    clusterName,
195	    clusterValidation,
196	    requiredODFVersion,
197	    t
198	  );
199	  const isClusterWithoutODF =
200	    clusterValidation.clustersWithoutODF.includes(clusterName);
201	  const title = isClusterWithoutODF
202	    ? t('Checks cannot be performed for the {{clusterName}}:', { clusterName })
203	    : pluralize(
204	        errorMessages.length,
205	        t('check unsuccessful on the {{clusterName}}:', { clusterName }),
206	        t('checks unsuccessful on the {{clusterName}}:', { clusterName })
207	      );
208	
209	  return (
210	    <div className="pf-v6-u-mt-md">
211	      <Text component={TextVariants.h5}>{title}</Text>
212	      {isClusterWithoutODF ? (
213	        <Alert
214	          data-test="odf-not-found-alert"
215	          className="odf-alert mco-create-data-policy__alert"
216	          title={t(
217	            'We could not retrieve any information about the managed cluster {{clusterName}}',
218	            { clusterName }
219	          )}
220	          variant={AlertVariant.danger}
221	          isInline
222	        />
223	      ) : (
224	        errorMessages.map((errorMessage, index) => (
225	          <StatusIconAndText
226	            className="pf-v6-u-ml-sm"
227	            icon={<TimesIcon color="var(--pf-global--danger-color--100)" />}
228	            title={errorMessage}
229	            key={`${clusterName}-error-${index}`}
230	          />
231	        ))
232	      )}
233	    </div>
234	  );
235	};
236	
237	const PeeringValidationMessage: React.FC<PeeringValidationMessageProps> = ({
238	  peeringValidation,
239	}) => {
240	  const { t } = useCustomTranslation();
241	  const peeringValidationMessage: PeeringValidationMessageType =
242	    getPeeringValidationMessage(peeringValidation, t);
243	  return (
244	    <Alert
245	      data-test="odf-not-found-alert"
246	      className="odf-alert mco-create-data-policy__alert"
247	      title={peeringValidationMessage.title}
248	      variant={AlertVariant.danger}
249	      isInline
250	    >
251	      {peeringValidationMessage.description}
252	    </Alert>
253	  );
254	};
255	
256	// Fetch provisioner if missing
257	const fetchProvisionerIfMissing = async (
258	  scName: string,
259	  clusterName: string,
260	  t: TFunction
261	) => {
262	  const viewResponse = await fireManagedClusterView(
263	    scName,
264	    '',
265	    StorageClassModel.kind,
266	    StorageClassModel.apiVersion,
267	    StorageClassModel.apiGroup,
268	    clusterName,
269	    t
270	  );
271	  return viewResponse;
272	};
273	
274	// Build cluster-to-SC map with provisioner validation
275	export const getClusterToSCMap = async (
276	  searchResult: SearchResult,
277	  searchLoaded: boolean,
278	  searchError: any,
279	  t: TFunction
280	): Promise<Map<ClusterNameType, string[]>> => {
281	  const clusterToSCMap: Map<ClusterNameType, string[]> = new Map();
282	
283	  if (searchLoaded && !searchError) {
284	    const allSCs =
285	      searchResult.data.searchResult?.flatMap((result) => result.items) || [];
286	    const provisionerResults = await Promise.all(
287	      allSCs.map(async (sc) => {
288	        const clusterName = sc.cluster;
289	        let provisioner: string = sc?.[PROVISIONER] ?? '';
290	
291	        // Fetch missing provisioner if necessary
292	        if (!provisioner) {
293	          const viewResponse = await fetchProvisionerIfMissing(
294	            sc.name,
295	            clusterName,
296	            t
297	          );
298	          provisioner = viewResponse.result?.[PROVISIONER] ?? '';
299	        }
300	
301	        const storageID = getStorageID(sc);
302	        if (
303	          (isValidCephProvisioner(provisioner) ||
304	            isValidIBMProvisioner(provisioner)) &&
305	          storageID !== ''
306	        ) {
307	          const scString = formatStorageClassString(sc.name, provisioner);
308	
309	          return { clusterName, scString };
310	        } else {
311	          // eslint-disable-next-line no-console
312	          console.warn(`Skipping invalid provisioner: ${provisioner}`);
313	          return null; // Return null for skipped ones
314	        }
315	      })
316	    );
317	
318	    // Populate the map from the results
319	    provisionerResults
320	      .filter(Boolean) // Remove null entries from invalid provisioners
321	      .forEach(({ clusterName, scString }) => {
322	        const existingSCs = clusterToSCMap.get(clusterName) ?? [];
323	        existingSCs.push(scString);
324	        clusterToSCMap.set(clusterName, existingSCs);
325	      });
326	  }
327	
328	  return clusterToSCMap;
329	};
330	
331	// Optimized comparison using Set
332	const findSupportedStorageClasses = (
333	  firstClusterSCs: string[],
334	  secondClusterSCs: string[]
335	): boolean => {
336	  const secondClusterSet = new Set(secondClusterSCs);
337	  return firstClusterSCs.some((sc) => secondClusterSet.has(sc));
338	};
339	
340	// Ensure both clusters have at least pair of valid storage class
341	const validateClusterDetails = (
342	  clusterToSCMap: Map<ClusterNameType, string[]>
343	): boolean => {
344	  const [firstClusterSCs = [], secondClusterSCs = []] = Array.from(
345	    clusterToSCMap.values()
346	  );
347	
348	  return findSupportedStorageClasses(firstClusterSCs, secondClusterSCs);
349	};
350	
351	// Main hook for storage class validation
352	const useStorageClassValidation = (
353	  selectedClusters: ManagedClusterInfoType[],
354	  t: TFunction
355	): [boolean, boolean, any] => {
356	  const [result, setResult] = React.useState<boolean>(false);
357	  const [isCompleted, setCompleted] = React.useState(false);
358	  const [clusterSCMapError, setClusterSCMapError] = React.useState<
359	    string | null
360	  >(null);
361	
362	  // Early return if both clusters are "external"
363	  const allExternal = selectedClusters.every(
364	    (cluster) =>
365	      cluster.odfInfo?.storageClusterInfo?.deploymentType ===
366	      EXTERNAL_DEPLOYMENT_TYPE
367	  );
368	
369	  const searchQuery = React.useMemo(
370	    () => queryStorageClassesUsingClusterNames(selectedClusters.map(getName)),
371	    [selectedClusters]
372	  );
373	
374	  const [searchResult, searchError, searchLoaded] =
375	    useACMSafeFetch(searchQuery);
376	
377	  React.useEffect(() => {
378	    if (!allExternal) {
379	      setCompleted(false);
380	      if (searchLoaded && !searchError) {
381	        getClusterToSCMap(searchResult, searchLoaded, searchError, t)
382	          .then((clusterToSCMap) => {
383	            setResult(validateClusterDetails(clusterToSCMap));
384	            setCompleted(true);
385	          })
386	          .catch((error) => {
387	            setClusterSCMapError(
388	              error instanceof Error
389	                ? error.message
390	                : t('something went wrong while getting storageclasses')
391	            );
392	            setCompleted(true);
393	          });
394	      } else if (searchError) {
395	        setCompleted(true);
396	      }
397	    } else {
398	      // Ignore validation for external clusters
399	      setResult(true);
400	      setCompleted(true);
401	    }
402	  }, [
403	    allExternal,
404	    searchResult,
405	    searchError,
406	    searchLoaded,
407	    t,
408	    setCompleted,
409	    setResult,
410	  ]);
411	
412	  return [result, isCompleted, searchError || clusterSCMapError];
413	};
414	
415	// Helper functions
416	const getStorageID = (sc: SearchResultItemType) => {
417	  return getLabelsFromSearchResult(sc)?.[STORAGE_ID_LABEL_KEY]?.[0] ?? '';
418	};
419	
420	const formatStorageClassString = (name: string, provisioner: string) => {
421	  return `${name}/${provisioner}`;
422	};
423	
424	const isValidCephProvisioner = (provisioner: string) => {
425	  return CEPH_PROVISIONERS.some((allowedProvisioner) =>
426	    provisioner.includes(allowedProvisioner)
427	  );
428	};
429	const isValidIBMProvisioner = (provisioner: string) => {
430	  return IBM_PROVISIONERS.some((allowedProvisioner) =>
431	    provisioner.includes(allowedProvisioner)
432	  );
433	};
434	
435	export const SelectedClusterValidation: React.FC<
436	  SelectedClusterValidationProps
437	> = ({ selectedClusters, requiredODFVersion, dispatch, mirrorPeers }) => {
438	  const { t } = useCustomTranslation();
439	
440	  // Fetch policies and storage class validation in parallel
441	  const [drPolicies, policyLoaded, policyLoadError] = useK8sWatchResource<
442	    DRPolicyKind[]
443	  >(getDRPolicyResourceObj());
444	  const [isValidStorageClasses, scLoaded, scLoadError] =
445	    useStorageClassValidation(selectedClusters, t);
446	
447	  // Consolidate loading and error states
448	  const loaded = policyLoaded && scLoaded;
449	  const loadError = policyLoadError || scLoadError;
450	
451	  // Memoized validations
452	  const validations: ValidationType = React.useMemo(
453	    () =>
454	      validateClusterSelection(
455	        selectedClusters,
456	        drPolicies,
457	        mirrorPeers,
458	        isValidStorageClasses
459	      ),
460	    [selectedClusters, drPolicies, mirrorPeers, isValidStorageClasses]
461	  );
462	
463	  const { peeringValidation, clusterValidation } = validations;
464	
465	  // Extract invalid clusters without memo
466	  const invalidClusters: string[] = Array.from(
467	    new Set([].concat(...Object.values(clusterValidation)))
468	  );
469	
470	  // Determine peering validity
471	  const isInvalidPeering = Object.values(peeringValidation).some(Boolean);
472	
473	  // Determine selection validity
474	  const isSelectionValid = !isInvalidPeering && !invalidClusters.length;
475	
476	  // Dispatch selection validation state
477	  React.useEffect(() => {
478	    if (loaded && !loadError) {
479	      dispatch({
480	        type: DRPolicyActionType.SET_CLUSTER_SELECTION_VALIDATION,
481	        payload: isSelectionValid,
482	      });
483	    }
484	  }, [isSelectionValid, loaded, loadError, dispatch]);
485	
486	  // Check for version mismatch
487	  const isVersionMismatch =
488	    selectedClusters[0]?.odfInfo?.odfVersion !==
489	    selectedClusters[1]?.odfInfo?.odfVersion;
490	
491	  return (
492	    <StatusBox
493	      data={selectedClusters}
494	      loaded={loaded}
495	      loadError={loadError}
496	      skeleton={
497	        <StatusIconAndText
498	          icon={<Spinner size="sm" />}
499	          title={t(
500	            'Running checks to ensure that the selected managed cluster meets all necessary conditions so it can enroll in a Disaster Recovery policy.'
501	          )}
502	        />
503	      }
504	    >
505	      {isSelectionValid ? (
506	        <>
507	          <Alert
508	            data-test="odf-not-found-alert"
509	            className="odf-alert mco-create-data-policy__alert"
510	            title={t(
511	              'All disaster recovery prerequisites met for both clusters.'
512	            )}
513	            variant={AlertVariant.success}
514	            isInline
515	          />
516	          {isVersionMismatch && (
517	            <Alert
518	              data-test="odf-not-found-alert"
519	              className="odf-alert mco-create-data-policy__alert"
520	              title={t('Version mismatch across selected clusters')}
521	              variant={AlertVariant.warning}
522	              isInline
523	            >
524	              {t(
525	                'The selected clusters are running different versions of Data Foundation. Peering clusters with different versions can lead to potential issues and is not recommended. Ensure all clusters are upgraded to the same version before proceeding with peering to avoid operational risks.'
526	              )}
527	            </Alert>
528	          )}
529	        </>
530	      ) : isInvalidPeering ? (
531	        <PeeringValidationMessage peeringValidation={peeringValidation} />
532	      ) : (
533	        <>
534	          <Alert
535	            data-test="odf-not-found-alert"
536	            className="odf-alert mco-create-data-policy__alert"
537	            title={t(
538	              '1 or more clusters do not meet disaster recovery cluster prerequisites.'
539	            )}
540	            variant={AlertVariant.danger}
541	            isInline
542	          >
543	            {t(
544	              'The selected managed cluster(s) does not meet all necessary conditions to be eligible for disaster recovery policy. Resolve the following issues to proceed with policy creation.'
545	            )}
546	          </Alert>
547	          {invalidClusters.map((clusterName) => (
548	            <ClusterValidationMessage
549	              clusterValidation={clusterValidation}
550	              clusterName={clusterName}
551	              requiredODFVersion={requiredODFVersion}
552	              key={clusterName}
553	            />
554	          ))}
555	        </>
556	      )}
557	    </StatusBox>
558	  );
559	};
560	
561	type SelectedClusterValidationProps = {
562	  selectedClusters: ManagedClusterInfoType[];
563	  requiredODFVersion: string;
564	  dispatch: React.Dispatch<DRPolicyAction>;
565	  mirrorPeers: MirrorPeerKind[];
566	};
567	
568	type PeeringValidationType = {
569	  unSupportedPeering: boolean;
570	  invalidPolicyCreation: boolean;
571	  unSupportedStorageClasses: boolean;
572	};
573	
574	type ClusterValidationType = {
575	  clustersWithUnsupportedODF: string[];
576	  clustersWithoutODF: string[];
577	  clustersWithUnsuccessfullODF: string[];
578	  clustersWithMultipleStorageInstances: string[];
579	};
580	
581	type ValidationType = {
582	  clusterValidation: ClusterValidationType;
583	  peeringValidation: PeeringValidationType;
584	};
585	
586	type ClusterValidationMessageProps = {
587	  clusterName: string;
588	  clusterValidation: ClusterValidationType;
589	  requiredODFVersion: string;
590	};
591	
592	type PeeringValidationMessageProps = {
593	  peeringValidation: PeeringValidationType;
594	};
595	
596	type PeeringValidationMessageType = {
597	  title: string;
598	  description?: React.ReactNode;
599	};
600	
601	type ClusterNameType = string;

